using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Channels;
using System.Threading.Tasks;

public static class Pipeline
{
    public static async Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count == 0) return 0;

        var channel = Channel.CreateBounded<int>(new BoundedChannelOptions(count));

        var producerTask = Task.Run(async () =>
        {
            for (int i = 0; i < count; i++)
            {
                await channel.Writer.WriteAsync(i);
            }
            await channel.Writer.Complete();
        });

        var consumerTask = Task.Run(async () =>
        {
            long sum = 0;
            while (await channel.Reader.WaitToReadAsync())
            {
                while (channel.Reader.TryRead(out int value))
                {
                    sum += value;
                }
            }
            return sum;
        });

        await Task.WhenAll(producerTask, consumerTask);

        return consumerTask.Result;
    }
}
