using System;

public static class TextScan
{
    public static int CountWords(ReadOnlySpan<char> text)
    {
        bool inWord = false;
        int wordCount = 0;

        foreach (char c in text)
        {
            if (char.IsWhiteSpace(c))
            {
                if (inWord)
                {
                    wordCount++;
                    inWord = false;
                }
            }
            else
            {
                inWord = true;
            }
        }

        return inWord ? wordCount + 1 : wordCount;
    }
}
