using System;
using System.Buffers;

public static class SpanParser
{
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        if (csv.Length == 0) return 0;

        int sum = 0;
        bool negative = false;
        int currentNumber = 0;

        for (int i = 0; i < csv.Length; i++)
        {
            char c = csv[i];

            if (c == '-')
            {
                if (i > 0) break;
                negative = true;
                continue;
            }

            if (c >= '0' && c <= '9')
            {
                currentNumber = currentNumber * 10 + (c - '0');
            }
            else if (c == ',')
            {
                sum += negative ? -currentNumber : currentNumber;
                currentNumber = 0;
                negative = false;
            }
        }

        return sum + (negative ? -currentNumber : currentNumber);
    }
}
